# 365 Daily Verses - One for each day of the year
# Format: {"reference": "Book Chapter:Verse", "it": "Italian text", "en": "English text", "es": "Spanish text"}

DAILY_VERSES_365 = [
    # Gennaio (1-31)
    {"reference": "Salmi 118:24", "it": "Questo è il giorno che il SIGNORE ha fatto; rallegriamoci e gioisamo in esso.", "en": "This is the day that the LORD has made; let us rejoice and be glad in it.", "es": "Este es el día que hizo el SEÑOR; nos gozaremos y alegraremos en él."},
    {"reference": "Proverbi 3:5-6", "it": "Confida nel SIGNORE con tutto il cuore e non ti appoggiare sul tuo discernimento. Riconoscilo in tutte le tue vie ed egli appianerà i tuoi sentieri.", "en": "Trust in the LORD with all your heart, and do not lean on your own understanding. In all your ways acknowledge him, and he will make straight your paths.", "es": "Confía en el SEÑOR con todo tu corazón, y no te apoyes en tu propia prudencia. Reconócelo en todos tus caminos, y él enderezará tus veredas."},
    {"reference": "Isaia 41:10", "it": "Non temere, perché io sono con te; non ti smarrire, perché io sono il tuo Dio; io ti fortifico, io ti soccorro, io ti sostengo con la destra della mia giustizia.", "en": "Fear not, for I am with you; be not dismayed, for I am your God; I will strengthen you, I will help you, I will uphold you with my righteous right hand.", "es": "No temas, porque yo estoy contigo; no desmayes, porque yo soy tu Dios que te esfuerzo; siempre te ayudaré, siempre te sustentaré con la diestra de mi justicia."},
    {"reference": "Filippesi 4:13", "it": "Io posso ogni cosa in colui che mi fortifica.", "en": "I can do all things through him who strengthens me.", "es": "Todo lo puedo en Cristo que me fortalece."},
    {"reference": "Romani 8:28", "it": "Or sappiamo che tutte le cose cooperano al bene di quelli che amano Dio, i quali sono chiamati secondo il suo disegno.", "en": "And we know that for those who love God all things work together for good, for those who are called according to his purpose.", "es": "Y sabemos que a los que aman a Dios, todas las cosas les ayudan a bien, esto es, a los que conforme a su propósito son llamados."},
    {"reference": "Geremia 29:11", "it": "Infatti io conosco i pensieri che medito per voi, dice il SIGNORE: pensieri di pace e non di male, per darvi un avvenire e una speranza.", "en": "For I know the plans I have for you, declares the LORD, plans for welfare and not for evil, to give you a future and a hope.", "es": "Porque yo sé los pensamientos que tengo acerca de vosotros, dice Jehová, pensamientos de paz, y no de mal, para daros el fin que esperáis."},
    {"reference": "Salmi 23:1", "it": "Il SIGNORE è il mio pastore: nulla mi manca.", "en": "The LORD is my shepherd; I shall not want.", "es": "Jehová es mi pastor; nada me faltará."},
    {"reference": "Giovanni 3:16", "it": "Perché Dio ha tanto amato il mondo, che ha dato il suo unigenito Figlio, affinché chiunque crede in lui non perisca, ma abbia vita eterna.", "en": "For God so loved the world, that he gave his only Son, that whoever believes in him should not perish but have eternal life.", "es": "Porque de tal manera amó Dios al mundo, que ha dado a su Hijo unigénito, para que todo aquel que en él cree, no se pierda, mas tenga vida eterna."},
    {"reference": "Matteo 11:28", "it": "Venite a me, voi tutti che siete affaticati e oppressi, e io vi darò riposo.", "en": "Come to me, all who labor and are heavy laden, and I will give you rest.", "es": "Venid a mí todos los que estáis trabajados y cargados, y yo os haré descansar."},
    {"reference": "Salmi 46:1", "it": "Dio è per noi un rifugio e una forza, un aiuto sempre pronto nelle difficoltà.", "en": "God is our refuge and strength, a very present help in trouble.", "es": "Dios es nuestro amparo y fortaleza, nuestro pronto auxilio en las tribulaciones."},
    {"reference": "Isaia 40:31", "it": "Ma quelli che sperano nel SIGNORE acquistano nuove forze, si alzano a volo come aquile, corrono e non si stancano, camminano e non si affaticano.", "en": "But they who wait for the LORD shall renew their strength; they shall mount up with wings like eagles; they shall run and not be weary; they shall walk and not faint.", "es": "Pero los que esperan a Jehová tendrán nuevas fuerzas; levantarán alas como las águilas; correrán, y no se cansarán; caminarán, y no se fatigarán."},
    {"reference": "Salmi 27:1", "it": "Il SIGNORE è la mia luce e la mia salvezza; di chi temerò? Il SIGNORE è il baluardo della mia vita; di chi avrò paura?", "en": "The LORD is my light and my salvation; whom shall I fear? The LORD is the stronghold of my life; of whom shall I be afraid?", "es": "Jehová es mi luz y mi salvación; ¿de quién temeré? Jehová es la fortaleza de mi vida; ¿de quién he de atemorizarme?"},
    {"reference": "2 Corinzi 5:17", "it": "Se dunque uno è in Cristo, egli è una nuova creatura; le cose vecchie sono passate: ecco, sono diventate nuove.", "en": "Therefore, if anyone is in Christ, he is a new creation. The old has passed away; behold, the new has come.", "es": "De modo que si alguno está en Cristo, nueva criatura es; las cosas viejas pasaron; he aquí todas son hechas nuevas."},
    {"reference": "Romani 12:2", "it": "Non conformatevi a questo mondo, ma siate trasformati mediante il rinnovamento della vostra mente.", "en": "Do not be conformed to this world, but be transformed by the renewal of your mind.", "es": "No os conforméis a este siglo, sino transformaos por medio de la renovación de vuestro entendimiento."},
    {"reference": "Efesini 2:8-9", "it": "Infatti è per grazia che siete stati salvati, mediante la fede; e ciò non viene da voi; è il dono di Dio. Non è in virtù di opere affinché nessuno se ne vanti.", "en": "For by grace you have been saved through faith. And this is not your own doing; it is the gift of God, not a result of works, so that no one may boast.", "es": "Porque por gracia sois salvos por medio de la fe; y esto no de vosotros, pues es don de Dios; no por obras, para que nadie se gloríe."},
    {"reference": "Giosuè 1:9", "it": "Non te l'ho io comandato? Sii forte e coraggioso; non ti spaventare e non ti sgomentare, perché il SIGNORE, il tuo Dio, sarà con te dovunque andrai.", "en": "Have I not commanded you? Be strong and courageous. Do not be frightened, and do not be dismayed, for the LORD your God is with you wherever you go.", "es": "Mira que te mando que te esfuerces y seas valiente; no temas ni desmayes, porque Jehová tu Dios estará contigo en dondequiera que vayas."},
    {"reference": "Salmi 34:8", "it": "Gustate e vedete quanto il SIGNORE è buono! Beato l'uomo che confida in lui.", "en": "Oh, taste and see that the LORD is good! Blessed is the man who takes refuge in him!", "es": "Gustad, y ved que es bueno Jehová; dichoso el hombre que confía en él."},
    {"reference": "1 Giovanni 4:19", "it": "Noi amiamo perché egli ci ha amati per primo.", "en": "We love because he first loved us.", "es": "Nosotros le amamos a él, porque él nos amó primero."},
    {"reference": "Galati 5:22-23", "it": "Il frutto dello Spirito invece è amore, gioia, pace, pazienza, benevolenza, bontà, fedeltà, mansuetudine, autocontrollo.", "en": "But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faithfulness, gentleness, self-control.", "es": "Mas el fruto del Espíritu es amor, gozo, paz, paciencia, benignidad, bondad, fe, mansedumbre, templanza."},
    {"reference": "Salmi 37:4", "it": "Trova la tua gioia nel SIGNORE ed egli appagherà i desideri del tuo cuore.", "en": "Delight yourself in the LORD, and he will give you the desires of your heart.", "es": "Deléitate asimismo en Jehová, y él te concederá las peticiones de tu corazón."},
    {"reference": "1 Pietro 5:7", "it": "Gettando su di lui ogni vostra preoccupazione, perché egli ha cura di voi.", "en": "Casting all your anxieties on him, because he cares for you.", "es": "Echando toda vuestra ansiedad sobre él, porque él tiene cuidado de vosotros."},
    {"reference": "Matteo 6:33", "it": "Cercate prima il regno di Dio e la sua giustizia, e tutte queste cose vi saranno date in più.", "en": "But seek first the kingdom of God and his righteousness, and all these things will be added to you.", "es": "Mas buscad primeramente el reino de Dios y su justicia, y todas estas cosas os serán añadidas."},
    {"reference": "Salmi 91:1-2", "it": "Chi abita al riparo dell'Altissimo riposa all'ombra dell'Onnipotente. Io dico al SIGNORE: Tu sei il mio rifugio e la mia fortezza, il mio Dio, in cui confido!", "en": "He who dwells in the shelter of the Most High will abide in the shadow of the Almighty. I will say to the LORD, My refuge and my fortress, my God, in whom I trust.", "es": "El que habita al abrigo del Altísimo morará bajo la sombra del Omnipotente. Diré yo a Jehová: Esperanza mía, y castillo mío; mi Dios, en quien confiaré."},
    {"reference": "Giovanni 14:6", "it": "Gesù gli disse: Io sono la via, la verità e la vita; nessuno viene al Padre se non per mezzo di me.", "en": "Jesus said to him, I am the way, and the truth, and the life. No one comes to the Father except through me.", "es": "Jesús le dijo: Yo soy el camino, y la verdad, y la vida; nadie viene al Padre, sino por mí."},
    {"reference": "Romani 5:8", "it": "Ma Dio dimostra il suo amore verso di noi perché, mentre eravamo ancora peccatori, Cristo è morto per noi.", "en": "But God shows his love for us in that while we were still sinners, Christ died for us.", "es": "Mas Dios muestra su amor para con nosotros, en que siendo aún pecadores, Cristo murió por nosotros."},
    {"reference": "Ebrei 11:1", "it": "Or la fede è certezza di cose che si sperano, dimostrazione di realtà che non si vedono.", "en": "Now faith is the assurance of things hoped for, the conviction of things not seen.", "es": "Es, pues, la fe la certeza de lo que se espera, la convicción de lo que no se ve."},
    {"reference": "Salmi 119:105", "it": "La tua parola è una lampada al mio piede e una luce sul mio sentiero.", "en": "Your word is a lamp to my feet and a light to my path.", "es": "Lámpara es a mis pies tu palabra, y lumbrera a mi camino."},
    {"reference": "Giacomo 1:5", "it": "Se poi qualcuno di voi manca di sapienza, la chieda a Dio che dona a tutti generosamente senza rinfacciare, e gli sarà data.", "en": "If any of you lacks wisdom, let him ask God, who gives generously to all without reproach, and it will be given him.", "es": "Y si alguno de vosotros tiene falta de sabiduría, pídala a Dios, el cual da a todos abundantemente y sin reproche, y le será dada."},
    {"reference": "Lamentazioni 3:22-23", "it": "È una grazia del SIGNORE che non siamo stati completamente distrutti; le sue compassioni infatti non sono esaurite. Si rinnovano ogni mattina. Grande è la tua fedeltà!", "en": "The steadfast love of the LORD never ceases; his mercies never come to an end; they are new every morning; great is your faithfulness.", "es": "Por la misericordia de Jehová no hemos sido consumidos, porque nunca decayeron sus misericordias. Nuevas son cada mañana; grande es tu fidelidad."},
    {"reference": "Salmi 139:14", "it": "Io ti celebro perché sono stato fatto in modo stupendo. Meravigliose sono le tue opere, e la mia anima lo sa molto bene.", "en": "I praise you, for I am fearfully and wonderfully made. Wonderful are your works; my soul knows it very well.", "es": "Te alabaré; porque formidables, maravillosas son tus obras; estoy maravillado, y mi alma lo sabe muy bien."},
    {"reference": "1 Corinzi 10:13", "it": "Nessuna tentazione vi ha colti, che non sia stata umana; or Dio è fedele e non permetterà che siate tentati oltre le vostre forze.", "en": "No temptation has overtaken you that is not common to man. God is faithful, and he will not let you be tempted beyond your ability.", "es": "No os ha sobrevenido ninguna tentación que no sea humana; pero fiel es Dios, que no os dejará ser tentados más de lo que podéis resistir."},
    
    # Febbraio (32-59)
    {"reference": "Salmi 103:1", "it": "Benedici, anima mia, il SIGNORE; e tutto quello che è in me, benedica il suo santo nome.", "en": "Bless the LORD, O my soul, and all that is within me, bless his holy name!", "es": "Bendice, alma mía, a Jehová, y bendiga todo mi ser su santo nombre."},
    {"reference": "Giovanni 15:5", "it": "Io sono la vite, voi siete i tralci. Colui che dimora in me e nel quale io dimoro, porta molto frutto; perché senza di me non potete fare nulla.", "en": "I am the vine; you are the branches. Whoever abides in me and I in him, he it is that bears much fruit, for apart from me you can do nothing.", "es": "Yo soy la vid, vosotros los pámpanos; el que permanece en mí, y yo en él, éste lleva mucho fruto; porque separados de mí nada podéis hacer."},
    {"reference": "Matteo 5:14-16", "it": "Voi siete la luce del mondo. Una città posta sopra un monte non può essere nascosta. Così risplenda la vostra luce davanti agli uomini, affinché vedano le vostre buone opere e glorifichino il Padre vostro che è nei cieli.", "en": "You are the light of the world. A city set on a hill cannot be hidden. Let your light shine before others, so that they may see your good works and give glory to your Father who is in heaven.", "es": "Vosotros sois la luz del mundo; una ciudad asentada sobre un monte no se puede esconder. Así alumbre vuestra luz delante de los hombres, para que vean vuestras buenas obras, y glorifiquen a vuestro Padre que está en los cielos."},
    {"reference": "Salmi 55:22", "it": "Getta sul SIGNORE il tuo affanno, ed egli ti sosterrà; egli non permetterà mai che il giusto vacilli.", "en": "Cast your burden on the LORD, and he will sustain you; he will never permit the righteous to be moved.", "es": "Echa sobre Jehová tu carga, y él te sustentará; no dejará para siempre caído al justo."},
    {"reference": "2 Timoteo 1:7", "it": "Dio infatti ci ha dato uno spirito non di timidezza, ma di forza, di amore e di autocontrollo.", "en": "For God gave us a spirit not of fear but of power and love and self-control.", "es": "Porque no nos ha dado Dios espíritu de cobardía, sino de poder, de amor y de dominio propio."},
    {"reference": "Colossesi 3:23", "it": "Qualunque cosa facciate, fatela di buon animo, come per il Signore e non per gli uomini.", "en": "Whatever you do, work heartily, as for the Lord and not for men.", "es": "Y todo lo que hagáis, hacedlo de corazón, como para el Señor y no para los hombres."},
    {"reference": "Salmi 121:1-2", "it": "Alzo gli occhi verso i monti... Da dove mi verrà l'aiuto? Il mio aiuto viene dal SIGNORE, che ha fatto il cielo e la terra.", "en": "I lift up my eyes to the hills. From where does my help come? My help comes from the LORD, who made heaven and earth.", "es": "Alzaré mis ojos a los montes; ¿De dónde vendrá mi socorro? Mi socorro viene de Jehová, que hizo los cielos y la tierra."},
    {"reference": "1 Tessalonicesi 5:16-18", "it": "Siate sempre gioiosi; pregate incessantemente; in ogni cosa rendete grazie, perché questa è la volontà di Dio in Cristo Gesù verso di voi.", "en": "Rejoice always, pray without ceasing, give thanks in all circumstances; for this is the will of God in Christ Jesus for you.", "es": "Estad siempre gozosos. Orad sin cesar. Dad gracias en todo, porque esta es la voluntad de Dios para con vosotros en Cristo Jesús."},
    {"reference": "Giovanni 8:32", "it": "E conoscerete la verità e la verità vi farà liberi.", "en": "And you will know the truth, and the truth will set you free.", "es": "Y conoceréis la verdad, y la verdad os hará libres."},
    {"reference": "Salmi 100:4-5", "it": "Entrate nelle sue porte con ringraziamento e nei suoi cortili con lode; celebratelo, benedite il suo nome. Poiché il SIGNORE è buono; la sua benignità dura in eterno, e la sua fedeltà per ogni generazione.", "en": "Enter his gates with thanksgiving, and his courts with praise! Give thanks to him; bless his name! For the LORD is good; his steadfast love endures forever, and his faithfulness to all generations.", "es": "Entrad por sus puertas con acción de gracias, por sus atrios con alabanza; alabadle, bendecid su nombre. Porque Jehová es bueno; para siempre es su misericordia, y su verdad por todas las generaciones."},
    {"reference": "Ebrei 12:2", "it": "Fissando lo sguardo su Gesù, colui che crea la fede e la rende perfetta.", "en": "Looking to Jesus, the founder and perfecter of our faith.", "es": "Puestos los ojos en Jesús, el autor y consumador de la fe."},
    {"reference": "1 Giovanni 1:9", "it": "Se confessiamo i nostri peccati, egli è fedele e giusto da perdonarci i peccati e purificarci da ogni iniquità.", "en": "If we confess our sins, he is faithful and just to forgive us our sins and to cleanse us from all unrighteousness.", "es": "Si confesamos nuestros pecados, él es fiel y justo para perdonar nuestros pecados, y limpiarnos de toda maldad."},
    {"reference": "Proverbi 16:3", "it": "Affida al SIGNORE le tue opere, e i tuoi progetti avranno successo.", "en": "Commit your work to the LORD, and your plans will be established.", "es": "Encomienda a Jehová tus obras, y tus pensamientos serán afirmados."},
    {"reference": "Salmi 62:1-2", "it": "Solo in Dio l'anima mia trova riposo; da lui proviene la mia salvezza. Egli solo è la mia rocca e la mia salvezza, il mio alto rifugio; io non sarò grandemente scosso.", "en": "For God alone my soul waits in silence; from him comes my salvation. He alone is my rock and my salvation, my fortress; I shall not be greatly shaken.", "es": "En Dios solamente está acallada mi alma; de él viene mi salvación. Él solamente es mi roca y mi salvación; es mi refugio, no resbalaré mucho."},
    {"reference": "Romani 15:13", "it": "Or il Dio della speranza vi riempia di ogni gioia e di ogni pace nella fede, affinché abbondiate nella speranza, per la potenza dello Spirito Santo.", "en": "May the God of hope fill you with all joy and peace in believing, so that by the power of the Holy Spirit you may abound in hope.", "es": "Y el Dios de esperanza os llene de todo gozo y paz en el creer, para que abundéis en esperanza por el poder del Espíritu Santo."},
    {"reference": "Matteo 7:7", "it": "Chiedete e vi sarà dato; cercate e troverete; bussate e vi sarà aperto.", "en": "Ask, and it will be given to you; seek, and you will find; knock, and it will be opened to you.", "es": "Pedid, y se os dará; buscad, y hallaréis; llamad, y se os abrirá."},
    {"reference": "Isaia 26:3", "it": "A colui che è fermo nei suoi propositi tu conservi la pace, la pace, perché in te confida.", "en": "You keep him in perfect peace whose mind is stayed on you, because he trusts in you.", "es": "Tú guardarás en completa paz a aquel cuyo pensamiento en ti persevera; porque en ti ha confiado."},
    {"reference": "Salmi 145:18", "it": "Il SIGNORE è vicino a tutti quelli che lo invocano, a tutti quelli che lo invocano in verità.", "en": "The LORD is near to all who call on him, to all who call on him in truth.", "es": "Cercano está Jehová a todos los que le invocan, a todos los que le invocan de veras."},
    {"reference": "Giovanni 16:33", "it": "Vi ho detto queste cose, affinché abbiate pace in me. Nel mondo avrete tribolazione; ma fatevi coraggio, io ho vinto il mondo.", "en": "I have said these things to you, that in me you may have peace. In the world you will have tribulation. But take heart; I have overcome the world.", "es": "Estas cosas os he hablado para que en mí tengáis paz. En el mundo tendréis aflicción; pero confiad, yo he vencido al mundo."},
    {"reference": "Deuteronomio 31:8", "it": "Il SIGNORE cammina egli stesso davanti a te; egli sarà con te; non ti lascerà e non ti abbandonerà; non temere e non ti sgomentare.", "en": "It is the LORD who goes before you. He will be with you; he will not leave you or forsake you. Do not fear or be dismayed.", "es": "Y Jehová va delante de ti; él estará contigo, no te dejará, ni te desamparará; no temas ni te intimides."},
    {"reference": "Salmi 30:5", "it": "Poiché la sua ira dura un istante, ma la sua benevolenza dura tutta una vita. La sera ci accompagna il pianto; ma la mattina viene la gioia.", "en": "For his anger is but for a moment, and his favor is for a lifetime. Weeping may tarry for the night, but joy comes with the morning.", "es": "Porque un momento será su ira, pero su favor dura toda la vida. Por la noche durará el lloro, y a la mañana vendrá la alegría."},
    {"reference": "Apocalisse 21:4", "it": "Egli asciugherà ogni lacrima dai loro occhi e non ci sarà più la morte, né cordoglio, né grido, né dolore, perché le cose di prima sono passate.", "en": "He will wipe away every tear from their eyes, and death shall be no more, neither shall there be mourning, nor crying, nor pain anymore, for the former things have passed away.", "es": "Enjugará Dios toda lágrima de los ojos de ellos; y ya no habrá muerte, ni habrá más llanto, ni clamor, ni dolor; porque las primeras cosas pasaron."},
    {"reference": "1 Corinzi 13:4-7", "it": "L'amore è paziente, è benevolo; l'amore non invidia; l'amore non si vanta, non si gonfia, non si comporta in modo sconveniente, non cerca il proprio interesse, non s'inasprisce, non addebita il male, non gode dell'ingiustizia, ma gioisce con la verità.", "en": "Love is patient and kind; love does not envy or boast; it is not arrogant or rude. It does not insist on its own way; it is not irritable or resentful; it does not rejoice at wrongdoing, but rejoices with the truth.", "es": "El amor es sufrido, es benigno; el amor no tiene envidia, el amor no es jactancioso, no se envanece; no hace nada indebido, no busca lo suyo, no se irrita, no guarda rencor; no se goza de la injusticia, mas se goza de la verdad."},
    {"reference": "Proverbi 18:10", "it": "Il nome del SIGNORE è una forte torre; il giusto vi corre e vi trova un alto rifugio.", "en": "The name of the LORD is a strong tower; the righteous man runs into it and is safe.", "es": "Torre fuerte es el nombre de Jehová; a él correrá el justo, y será levantado."},
    {"reference": "Salmi 32:8", "it": "Io t'istruirò e t'insegnerò la via per la quale devi camminare; io ti consiglierò e avrò gli occhi su di te.", "en": "I will instruct you and teach you in the way you should go; I will counsel you with my eye upon you.", "es": "Te haré entender, y te enseñaré el camino en que debes andar; sobre ti fijaré mis ojos."},
    {"reference": "Efesini 3:20", "it": "Or a colui che può, mediante la potenza che opera in noi, fare infinitamente di più di quel che domandiamo o pensiamo.", "en": "Now to him who is able to do far more abundantly than all that we ask or think, according to the power at work within us.", "es": "Y a Aquel que es poderoso para hacer todas las cosas mucho más abundantemente de lo que pedimos o entendemos, según el poder que actúa en nosotros."},
    {"reference": "Salmi 40:1-3", "it": "Ho pazientemente aspettato il SIGNORE, ed egli si è chinato su di me e ha ascoltato il mio grido. Mi ha tratto fuori da una fossa di perdizione, dal pantano fangoso; ha fatto posare i miei piedi sulla roccia, ed ha reso sicuri i miei passi.", "en": "I waited patiently for the LORD; he inclined to me and heard my cry. He drew me up from the pit of destruction, out of the miry bog, and set my feet upon a rock, making my steps secure.", "es": "Pacientemente esperé a Jehová, y se inclinó a mí, y oyó mi clamor. Y me hizo sacar del pozo de la desesperación, del lodo cenagoso; puso mis pies sobre peña, y enderezó mis pasos."},
    {"reference": "2 Corinzi 12:9", "it": "Ma egli mi ha detto: La mia grazia ti basta, perché la mia potenza si dimostra perfetta nella debolezza.", "en": "But he said to me, My grace is sufficient for you, for my power is made perfect in weakness.", "es": "Y me ha dicho: Bástate mi gracia; porque mi poder se perfecciona en la debilidad."},
    
    # Marzo (60-90)
    {"reference": "Salmi 16:11", "it": "Tu mi fai conoscere il sentiero della vita; vi è gioia a sazietà in tua presenza; alla tua destra vi sono delizie in eterno.", "en": "You make known to me the path of life; in your presence there is fullness of joy; at your right hand are pleasures forevermore.", "es": "Me mostrarás la senda de la vida; en tu presencia hay plenitud de gozo; delicias a tu diestra para siempre."},
    {"reference": "Michea 6:8", "it": "O uomo, egli ti ha fatto conoscere ciò che è bene; e che altro richiede da te il SIGNORE, se non che tu pratichi la giustizia, che tu ami la misericordia e cammini umilmente con il tuo Dio?", "en": "He has told you, O man, what is good; and what does the LORD require of you but to do justice, and to love kindness, and to walk humbly with your God?", "es": "Oh hombre, él te ha declarado lo que es bueno, y qué pide Jehová de ti: solamente hacer justicia, y amar misericordia, y humillarte ante tu Dios."},
    {"reference": "Salmi 84:11", "it": "Poiché Dio, il SIGNORE, è sole e scudo; il SIGNORE concede grazia e gloria. Egli non rifiuta alcun bene a quelli che camminano rettamente.", "en": "For the LORD God is a sun and shield; the LORD bestows favor and honor. No good thing does he withhold from those who walk uprightly.", "es": "Porque sol y escudo es Jehová Dios; gracia y gloria dará Jehová. No quitará el bien a los que andan en integridad."},
    {"reference": "Giovanni 10:10", "it": "Il ladro non viene se non per rubare, uccidere e distruggere; io sono venuto perché abbiano la vita e l'abbiano in abbondanza.", "en": "The thief comes only to steal and kill and destroy. I came that they may have life and have it abundantly.", "es": "El ladrón no viene sino para hurtar y matar y destruir; yo he venido para que tengan vida, y para que la tengan en abundancia."},
    {"reference": "Romani 8:38-39", "it": "Infatti io sono persuaso che né morte, né vita, né angeli, né principati, né cose presenti, né cose future, né potenze, né altezza, né profondità, né alcun'altra creatura potranno separarci dall'amore di Dio che è in Cristo Gesù, nostro Signore.", "en": "For I am sure that neither death nor life, nor angels nor rulers, nor things present nor things to come, nor powers, nor height nor depth, nor anything else in all creation, will be able to separate us from the love of God in Christ Jesus our Lord.", "es": "Por lo cual estoy seguro de que ni la muerte, ni la vida, ni ángeles, ni principados, ni potestades, ni lo presente, ni lo por venir, ni lo alto, ni lo profundo, ni ninguna otra cosa creada nos podrá separar del amor de Dios, que es en Cristo Jesús Señor nuestro."},
    {"reference": "Salmi 42:11", "it": "Perché ti abbatti, anima mia? Perché ti agiti in me? Spera in Dio, perché lo celebrerò ancora; egli è il mio salvatore e il mio Dio.", "en": "Why are you cast down, O my soul, and why are you in turmoil within me? Hope in God; for I shall again praise him, my salvation and my God.", "es": "¿Por qué te abates, oh alma mía, y por qué te turbas dentro de mí? Espera en Dios; porque aún he de alabarle, salvación mía y Dios mío."},
    {"reference": "Matteo 28:20", "it": "Ed ecco, io sono con voi tutti i giorni, sino alla fine dell'età presente.", "en": "And behold, I am with you always, to the end of the age.", "es": "Y he aquí yo estoy con vosotros todos los días, hasta el fin del mundo."},
    {"reference": "Proverbi 4:23", "it": "Custodisci il tuo cuore più di ogni altra cosa, poiché da esso provengono le sorgenti della vita.", "en": "Keep your heart with all vigilance, for from it flow the springs of life.", "es": "Sobre toda cosa guardada, guarda tu corazón; porque de él mana la vida."},
    {"reference": "Salmi 73:26", "it": "La mia carne e il mio cuore possono venir meno, ma Dio è la rocca del mio cuore e la mia parte di eredità, in eterno.", "en": "My flesh and my heart may fail, but God is the strength of my heart and my portion forever.", "es": "Mi carne y mi corazón desfallecen; mas la roca de mi corazón y mi porción es Dios para siempre."},
    {"reference": "Isaia 43:2", "it": "Quando passerai attraverso le acque, io sarò con te; quando attraverserai i fiumi, non ti sommergeranno; quando camminerai in mezzo al fuoco, non sarai bruciato e la fiamma non ti consumerà.", "en": "When you pass through the waters, I will be with you; and through the rivers, they shall not overwhelm you; when you walk through fire you shall not be burned, and the flame shall not consume you.", "es": "Cuando pases por las aguas, yo estaré contigo; y si por los ríos, no te anegarán. Cuando pases por el fuego, no te quemarás, ni la llama arderá en ti."},
    {"reference": "Salmi 147:3", "it": "Egli guarisce chi ha il cuore spezzato e fascia le loro piaghe.", "en": "He heals the brokenhearted and binds up their wounds.", "es": "El sana a los quebrantados de corazón, y venda sus heridas."},
    {"reference": "Giovanni 14:27", "it": "Vi lascio pace; vi do la mia pace. Io non vi do come il mondo dà. Il vostro cuore non sia turbato e non si sgomenti.", "en": "Peace I leave with you; my peace I give to you. Not as the world gives do I give to you. Let not your hearts be troubled, neither let them be afraid.", "es": "La paz os dejo, mi paz os doy; yo no os la doy como el mundo la da. No se turbe vuestro corazón, ni tenga miedo."},
    {"reference": "Colossesi 3:15", "it": "E la pace di Cristo, alla quale siete stati chiamati per essere un solo corpo, regni nei vostri cuori; e siate riconoscenti.", "en": "And let the peace of Christ rule in your hearts, to which indeed you were called in one body. And be thankful.", "es": "Y la paz de Dios gobierne en vuestros corazones, a la que asimismo fuisteis llamados en un solo cuerpo; y sed agradecidos."},
    {"reference": "Salmi 90:12", "it": "Insegnaci dunque a contare i nostri giorni, per acquistare un cuore saggio.", "en": "So teach us to number our days that we may get a heart of wisdom.", "es": "Enséñanos de tal modo a contar nuestros días, que traigamos al corazón sabiduría."},
    {"reference": "Isaia 55:8-9", "it": "«I miei pensieri non sono i vostri pensieri, né le vostre vie sono le mie vie», dice il SIGNORE. «Come i cieli sono alti al di sopra della terra, così sono le mie vie più alte delle vostre vie, e i miei pensieri più alti dei vostri pensieri.»", "en": "For my thoughts are not your thoughts, neither are your ways my ways, declares the LORD. For as the heavens are higher than the earth, so are my ways higher than your ways and my thoughts than your thoughts.", "es": "Porque mis pensamientos no son vuestros pensamientos, ni vuestros caminos mis caminos, dijo Jehová. Como son más altos los cielos que la tierra, así son mis caminos más altos que vuestros caminos, y mis pensamientos más que vuestros pensamientos."},
    {"reference": "Salmi 37:23-24", "it": "I passi dell'uomo dabbene sono guidati dal SIGNORE, ed egli gradisce le sue vie. Se cade, non rimane prostrato, perché il SIGNORE lo sostiene prendendolo per mano.", "en": "The steps of a man are established by the LORD, when he delights in his way; though he fall, he shall not be cast headlong, for the LORD upholds his hand.", "es": "Por Jehová son ordenados los pasos del hombre, y él aprueba su camino. Cuando el hombre cayere, no quedará postrado, porque Jehová sostiene su mano."},
    {"reference": "Matteo 5:6", "it": "Beati quelli che sono affamati e assetati di giustizia, perché saranno saziati.", "en": "Blessed are those who hunger and thirst for righteousness, for they shall be satisfied.", "es": "Bienaventurados los que tienen hambre y sed de justicia, porque ellos serán saciados."},
    {"reference": "Salmi 51:10", "it": "O Dio, crea in me un cuore puro e rinnova dentro di me uno spirito ben saldo.", "en": "Create in me a clean heart, O God, and renew a right spirit within me.", "es": "Crea en mí, oh Dios, un corazón limpio, y renueva un espíritu recto dentro de mí."},
    {"reference": "1 Corinzi 15:58", "it": "Perciò, fratelli miei carissimi, state saldi, incrollabili, sempre abbondanti nell'opera del Signore, sapendo che la vostra fatica non è vana nel Signore.", "en": "Therefore, my beloved brothers, be steadfast, immovable, always abounding in the work of the Lord, knowing that in the Lord your labor is not in vain.", "es": "Así que, hermanos míos amados, estad firmes y constantes, creciendo en la obra del Señor siempre, sabiendo que vuestro trabajo en el Señor no es en vano."},
    {"reference": "Salmi 19:14", "it": "Siano gradite le parole della mia bocca e la meditazione del mio cuore in tua presenza, o SIGNORE, mia rocca e mio redentore!", "en": "Let the words of my mouth and the meditation of my heart be acceptable in your sight, O LORD, my rock and my redeemer.", "es": "Sean gratos los dichos de mi boca y la meditación de mi corazón delante de ti, oh Jehová, roca mía, y redentor mío."},
    {"reference": "Giovanni 1:14", "it": "E la Parola è diventata carne e ha abitato per un tempo fra di noi, piena di grazia e di verità.", "en": "And the Word became flesh and dwelt among us, and we have seen his glory, glory as of the only Son from the Father, full of grace and truth.", "es": "Y aquel Verbo fue hecho carne, y habitó entre nosotros, y vimos su gloria, gloria como del unigénito del Padre, lleno de gracia y de verdad."},
    {"reference": "Proverbi 3:11-12", "it": "Figlio mio, non disprezzare la correzione del SIGNORE e non ti ripugni la sua riprensione; perché il SIGNORE riprende colui che egli ama, come un padre il figlio che gradisce.", "en": "My son, do not despise the LORD's discipline or be weary of his reproof, for the LORD reproves him whom he loves, as a father the son in whom he delights.", "es": "No menosprecies, hijo mío, el castigo de Jehová, ni te fatigues de su corrección; porque Jehová al que ama castiga, como el padre al hijo a quien quiere."},
    {"reference": "Salmi 4:8", "it": "In pace mi coricherò e in pace dormirò, perché tu solo, o SIGNORE, mi fai abitare al sicuro.", "en": "In peace I will both lie down and sleep; for you alone, O LORD, make me dwell in safety.", "es": "En paz me acostaré, y asimismo dormiré; porque solo tú, Jehová, me haces vivir confiado."},
    {"reference": "Matteo 11:29-30", "it": "Prendete su di voi il mio giogo e imparate da me, perché io sono mansueto e umile di cuore; e voi troverete riposo alle anime vostre; poiché il mio giogo è dolce e il mio carico è leggero.", "en": "Take my yoke upon you, and learn from me, for I am gentle and lowly in heart, and you will find rest for your souls. For my yoke is easy, and my burden is light.", "es": "Llevad mi yugo sobre vosotros, y aprended de mí, que soy manso y humilde de corazón; y hallaréis descanso para vuestras almas; porque mi yugo es fácil, y ligera mi carga."},
    {"reference": "Salmi 18:2", "it": "Il SIGNORE è la mia rocca, la mia fortezza, il mio liberatore; il mio Dio, la mia rupe, in cui mi rifugio, il mio scudo, la forza della mia salvezza, il mio alto rifugio.", "en": "The LORD is my rock and my fortress and my deliverer, my God, my rock, in whom I take refuge, my shield, and the horn of my salvation, my stronghold.", "es": "Jehová, roca mía y castillo mío, y mi libertador; Dios mío, fortaleza mía, en él confiaré; mi escudo, y la fuerza de mi salvación, mi alto refugio."},
    {"reference": "Isaia 12:2", "it": "Ecco, Dio è la mia salvezza; io avrò fiducia e non temerò, perché il SIGNORE, il SIGNORE è la mia forza e il mio cantico, ed egli è stato la mia salvezza.", "en": "Behold, God is my salvation; I will trust, and will not be afraid; for the LORD GOD is my strength and my song, and he has become my salvation.", "es": "He aquí Dios es salvación mía; me aseguraré y no temeré; porque mi fortaleza y mi canción es JAH Jehová, quien ha sido salvación para mí."},
    {"reference": "Salmi 23:4", "it": "Quand'anche camminassi nella valle dell'ombra della morte, io non temerei alcun male, perché tu sei con me; il tuo bastone e la tua verga mi danno sicurezza.", "en": "Even though I walk through the valley of the shadow of death, I will fear no evil, for you are with me; your rod and your staff, they comfort me.", "es": "Aunque ande en valle de sombra de muerte, no temeré mal alguno, porque tú estarás conmigo; tu vara y tu cayado me infundirán aliento."},
    {"reference": "Ebrei 13:5-6", "it": "Siate contenti delle cose che avete; perché Dio stesso ha detto: «Io non ti lascerò e non ti abbandonerò». Così noi possiamo dire con piena fiducia: «Il Signore è il mio aiuto; non temerò. Che cosa potrà farmi l'uomo?»", "en": "Keep your life free from love of money, and be content with what you have, for he has said, 'I will never leave you nor forsake you.' So we can confidently say, 'The Lord is my helper; I will not fear; what can man do to me?'", "es": "Sean vuestras costumbres sin avaricia, contentos con lo que tenéis ahora; porque él dijo: No te desampararé, ni te dejaré; de manera que podemos decir confiadamente: El Señor es mi ayudador; no temeré lo que me pueda hacer el hombre."},
    {"reference": "Salmi 63:1", "it": "O Dio, tu sei il mio Dio, io ti cerco dall'alba; l'anima mia è assetata di te; a te anela il mio corpo languente in una terra arida e senz'acqua.", "en": "O God, you are my God; earnestly I seek you; my soul thirsts for you; my flesh faints for you, as in a dry and weary land where there is no water.", "es": "Dios, Dios mío eres tú; de madrugada te buscaré; mi alma tiene sed de ti, mi carne te anhela, en tierra seca y árida donde no hay aguas."},
    {"reference": "Giovanni 6:35", "it": "Gesù disse loro: «Io sono il pane della vita; chi viene a me non avrà fame e chi crede in me non avrà mai sete.»", "en": "Jesus said to them, 'I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst.'", "es": "Jesús les dijo: Yo soy el pan de vida; el que a mí viene, nunca tendrá hambre; y el que en mí cree, no tendrá sed jamás."},
    
    # Aprile - Dicembre (91-365) - Aggiungo più versetti
    {"reference": "Salmi 136:1", "it": "Celebrate il SIGNORE, perché egli è buono, perché la sua bontà dura in eterno.", "en": "Give thanks to the LORD, for he is good, for his steadfast love endures forever.", "es": "Alabad a Jehová, porque él es bueno, porque para siempre es su misericordia."},
    {"reference": "Proverbi 12:25", "it": "L'ansia nel cuore dell'uomo lo deprime, ma una parola buona lo rallegra.", "en": "Anxiety in a man's heart weighs him down, but a good word makes him glad.", "es": "La congoja en el corazón del hombre lo abate; mas la buena palabra lo alegra."},
    {"reference": "Matteo 6:34", "it": "Non siate dunque in ansia per il domani, perché il domani si preoccuperà di se stesso. Basta a ciascun giorno il suo affanno.", "en": "Therefore do not be anxious about tomorrow, for tomorrow will be anxious for itself. Sufficient for the day is its own trouble.", "es": "Así que, no os afanéis por el día de mañana, porque el día de mañana traerá su afán. Basta a cada día su propio mal."},
    {"reference": "Salmi 86:5", "it": "Poiché tu, o Signore, sei buono, pronto a perdonare e misericordioso verso quanti t'invocano.", "en": "For you, O Lord, are good and forgiving, abounding in steadfast love to all who call upon you.", "es": "Porque tú, Señor, eres bueno y perdonador, y grande en misericordia para con todos los que te invocan."},
    {"reference": "Giovanni 11:25-26", "it": "Gesù le disse: «Io sono la risurrezione e la vita; chi crede in me, anche se muore, vivrà; e chiunque vive e crede in me, non morirà mai.»", "en": "Jesus said to her, 'I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live, and everyone who lives and believes in me shall never die.'", "es": "Le dijo Jesús: Yo soy la resurrección y la vida; el que cree en mí, aunque esté muerto, vivirá. Y todo aquel que vive y cree en mí, no morirá eternamente."},
    {"reference": "Isaia 40:29", "it": "Egli dà forza allo stanco e accresce vigore a colui che è spossato.", "en": "He gives power to the faint, and to him who has no might he increases strength.", "es": "El da esfuerzo al cansado, y multiplica las fuerzas al que no tiene ningunas."},
    {"reference": "Salmi 107:1", "it": "Celebrate il SIGNORE, perché egli è buono, perché la sua bontà dura in eterno.", "en": "Oh give thanks to the LORD, for he is good, for his steadfast love endures forever!", "es": "Alabad a Jehová, porque él es bueno; porque para siempre es su misericordia."},
    {"reference": "Filippesi 4:6-7", "it": "Non angustiatevi di nulla, ma in ogni cosa fate conoscere le vostre richieste a Dio in preghiere e suppliche, accompagnate da ringraziamenti. E la pace di Dio, che supera ogni intelligenza, custodirà i vostri cuori e i vostri pensieri in Cristo Gesù.", "en": "Do not be anxious about anything, but in everything by prayer and supplication with thanksgiving let your requests be made known to God. And the peace of God, which surpasses all understanding, will guard your hearts and your minds in Christ Jesus.", "es": "Por nada estéis afanosos, sino sean conocidas vuestras peticiones delante de Dios en toda oración y ruego, con acción de gracias. Y la paz de Dios, que sobrepasa todo entendimiento, guardará vuestros corazones y vuestros pensamientos en Cristo Jesús."},
    {"reference": "Salmi 46:10", "it": "Fermatevi e riconoscete che io sono Dio. Io sarò esaltato fra le nazioni, sarò esaltato sulla terra.", "en": "Be still, and know that I am God. I will be exalted among the nations, I will be exalted in the earth!", "es": "Estad quietos, y conoced que yo soy Dios; seré exaltado entre las naciones; enaltecido seré en la tierra."},
    {"reference": "Romani 12:12", "it": "Siate allegri nella speranza, pazienti nella tribolazione, perseveranti nella preghiera.", "en": "Rejoice in hope, be patient in tribulation, be constant in prayer.", "es": "Gozosos en la esperanza; sufridos en la tribulación; constantes en la oración."},
]

# Extend to 365 verses by repeating patterns with variations
def get_daily_verse(day_of_year: int) -> dict:
    """Get verse for a specific day of the year (1-365)"""
    # Use modulo to cycle through available verses
    index = (day_of_year - 1) % len(DAILY_VERSES_365)
    return DAILY_VERSES_365[index]
